11	// Guard decides whether a bead may proceed. Callers use the returned reason
12	// for skip telemetry and logs.
13	type Guard interface {
14		Allow(ctx context.Context, beadID string) (bool, string)
15	}
16	
17	// cooldownStore is the minimal store surface PreClaimGuard needs.
18	type cooldownStore interface {
19		SetExecutionCooldown(id string, until time.Time, status, detail string) error
20	}
21	
22	// PreClaimHook matches the execute-loop pre-claim hook signature.
23	type PreClaimHook func(ctx context.Context) error
24	
25	// PreClaimGuard implements the two-strikes pre-claim policy. The first hook
26	// failure skips the candidate and retries it on the next presentation; the
27	// second failure parks the bead on execution cooldown.
28	type PreClaimGuard struct {
29		hook     PreClaimHook
30		store    cooldownStore
31		log      io.Writer
32		now      func() time.Time
33		cooldown time.Duration
34	
35		mu         sync.Mutex
36		failCounts map[string]int
37	}
38	
39	// NewPreClaimGuard constructs a Guard that owns the pre-claim hook retry
40	// state for one worker run.
41	func NewPreClaimGuard(hook PreClaimHook, store cooldownStore, log io.Writer, now func() time.Time, cooldown time.Duration) *PreClaimGuard {
42		if now == nil {
43			now = time.Now
44		}
45		if cooldown <= 0 {
46			cooldown = 30 * time.Second
47		}
48		return &PreClaimGuard{
49			hook:       hook,
50			store:      store,
51			log:        log,
52			now:        now,
53			cooldown:   cooldown,
54			failCounts: make(map[string]int),
55		}
56	}
57	
58	// Allow runs the pre-claim hook and applies the two-strikes retry policy.
59	func (g *PreClaimGuard) Allow(ctx context.Context, beadID string) (bool, string) {
60		if g == nil || g.hook == nil {
61			return true, ""
62		}
63		if err := g.hook(ctx); err != nil {
64			g.mu.Lock()
65			defer g.mu.Unlock()
66	
67			g.failCounts[beadID]++
68			if g.failCounts[beadID] >= 2 {
69				if g.store != nil {
70					until := g.now().UTC().Add(g.cooldown)
71					_ = g.store.SetExecutionCooldown(beadID, until, "preclaim-hook-failed", err.Error())
72				}
73			}
74			if g.log != nil {
75				_, _ = fmt.Fprintf(g.log, "pre-claim hook: %v (skipping %s)\n", err, beadID)
76			}
77			return false, err.Error()
78		}
79	
80		g.mu.Lock()
81		delete(g.failCounts, beadID)
82		g.mu.Unlock()
83		return true, ""
84	}
